import{_ as i,o as e,c as s,a2 as n}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Diseno y arquitectura de pipelines","description":"","frontmatter":{},"headers":[],"relativePath":"data-engineering/pipelines/02-diseno-y-arquitectura.md","filePath":"data-engineering/pipelines/02-diseno-y-arquitectura.md","lastUpdated":1782521464000}'),l={name:"data-engineering/pipelines/02-diseno-y-arquitectura.md"};function t(o,a,r,d,p,c){return e(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="diseno-y-arquitectura-de-pipelines" tabindex="-1">Diseno y arquitectura de pipelines <a class="header-anchor" href="#diseno-y-arquitectura-de-pipelines" aria-label="Permalink to &quot;Diseno y arquitectura de pipelines&quot;">​</a></h1><p>El diseno de un pipeline empieza antes de elegir herramienta. La pregunta importante no es si usar Airflow, NiFi, Spark o dbt, sino que garantias necesita el flujo de datos.</p><h2 id="contrato-de-datos" tabindex="-1">Contrato de datos <a class="header-anchor" href="#contrato-de-datos" aria-label="Permalink to &quot;Contrato de datos&quot;">​</a></h2><p>Un contrato de datos describe que puede esperar el consumidor del dataset.</p><p>Debe incluir:</p><ul><li>Nombre del dataset.</li><li>Fuente original.</li><li>Propietario funcional y tecnico.</li><li>Frecuencia de actualizacion.</li><li>Campos, tipos y significado.</li><li>Claves primarias o claves naturales.</li><li>Campos obligatorios.</li><li>Reglas de calidad.</li><li>Politica de cambios de esquema.</li><li>Retencion y sensibilidad de los datos.</li></ul><p>Ejemplo:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dataset: fact_ventas</span></span>
<span class="line"><span>fuente: api_ventas</span></span>
<span class="line"><span>frecuencia: cada hora</span></span>
<span class="line"><span>clave: id_venta</span></span>
<span class="line"><span>campos obligatorios: id_venta, fecha, cliente_id, importe, moneda</span></span>
<span class="line"><span>SLA: disponible antes del minuto 15 de cada hora</span></span></code></pre></div><h2 id="fuente" tabindex="-1">Fuente <a class="header-anchor" href="#fuente" aria-label="Permalink to &quot;Fuente&quot;">​</a></h2><p>Analiza la fuente antes de programar:</p><ul><li>Si permite extraccion incremental.</li><li>Si tiene paginacion, limites o ventanas temporales.</li><li>Si expone fecha de modificacion.</li><li>Si puede entregar duplicados.</li><li>Si el esquema cambia sin aviso.</li><li>Si hay campos sensibles.</li><li>Si el orden de llegada importa.</li></ul><p>Una fuente sin contrato claro obliga al pipeline a defenderse mejor.</p><h2 id="destino" tabindex="-1">Destino <a class="header-anchor" href="#destino" aria-label="Permalink to &quot;Destino&quot;">​</a></h2><p>El destino condiciona el diseno:</p><ul><li>Un data lake prioriza trazabilidad, formato y particionado.</li><li>Un data warehouse prioriza modelos consultables y coste de consulta.</li><li>Una base operacional prioriza latencia y consistencia.</li><li>Un indice de busqueda prioriza documentos y actualizaciones parciales.</li><li>Un sistema de ML prioriza reproducibilidad de features.</li></ul><p>No disenes igual una tabla historica para analisis que una API que necesita datos recientes.</p><h2 id="separacion-de-responsabilidades" tabindex="-1">Separacion de responsabilidades <a class="header-anchor" href="#separacion-de-responsabilidades" aria-label="Permalink to &quot;Separacion de responsabilidades&quot;">​</a></h2><p>Un pipeline mantenible separa fases:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>extract -&gt; load raw -&gt; validate -&gt; transform -&gt; publish -&gt; monitor</span></span></code></pre></div><p>Evita mezclar demasiadas responsabilidades en el mismo paso. Por ejemplo, un unico script que llama una API, corrige datos, aplica reglas de negocio, escribe una tabla final y manda alertas sera dificil de probar y reprocesar.</p><h2 id="configuracion" tabindex="-1">Configuracion <a class="header-anchor" href="#configuracion" aria-label="Permalink to &quot;Configuracion&quot;">​</a></h2><p>La configuracion debe estar fuera de la logica principal:</p><ul><li>Rutas de entrada y salida.</li><li>Credenciales.</li><li>Ventanas de fechas.</li><li>Nombres de tablas.</li><li>Umbrales de calidad.</li><li>Parametros por entorno.</li></ul><p>Ejemplo:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">source</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">api_ventas</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">target_table</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">curated.fact_ventas</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">watermark_column</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">updated_at</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">quality</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  min_rows</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  required_columns</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">id_venta</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">fecha</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">importe</span></span></code></pre></div><h2 id="versionado" tabindex="-1">Versionado <a class="header-anchor" href="#versionado" aria-label="Permalink to &quot;Versionado&quot;">​</a></h2><p>Versiona todo lo que afecte al resultado:</p><ul><li>Codigo de transformacion.</li><li>Esquemas.</li><li>Consultas SQL.</li><li>Configuracion.</li><li>DAGs o flujos.</li><li>Jobs de despliegue.</li><li>Documentacion del contrato.</li></ul><p>Si no puedes saber que version produjo un dataset, sera dificil explicar diferencias entre ejecuciones.</p><h2 id="lineage" tabindex="-1">Lineage <a class="header-anchor" href="#lineage" aria-label="Permalink to &quot;Lineage&quot;">​</a></h2><p>El lineage responde:</p><ul><li>De donde viene este dato.</li><li>Que transformaciones se aplicaron.</li><li>Que datasets dependen de el.</li><li>Que se rompe si cambia una columna.</li></ul><p>Aunque no tengas una herramienta avanzada al principio, puedes empezar documentando entradas, salidas y dependencias en cada capitulo del pipeline.</p><h2 id="checklist-de-diseno" tabindex="-1">Checklist de diseno <a class="header-anchor" href="#checklist-de-diseno" aria-label="Permalink to &quot;Checklist de diseno&quot;">​</a></h2><ul><li>La fuente esta identificada y documentada.</li><li>El destino y el formato estan definidos.</li><li>Existe una clave para idempotencia o deduplicacion.</li><li>Los datos crudos se conservan.</li><li>Hay estrategia de errores y cuarentena.</li><li>El pipeline puede reprocesar una ventana concreta.</li><li>Hay metricas minimas de filas, duracion y fallos.</li><li>Hay propietario y runbook.</li></ul>`,35)])])}const k=i(l,[["render",t]]);export{h as __pageData,k as default};
